<# .SYNOPSIS Offline regression for immutable blindspot learning and correlation routing. #>
param([switch]$PassThru)
$ErrorActionPreference='Stop';$root=(Resolve-Path(Join-Path $PSScriptRoot '..\..')).Path;$tmp=Join-Path $root '.qianlima\tmp';New-Item -ItemType Directory -Path $tmp -Force|Out-Null;$obsPath=Join-Path $tmp 'blindspot-observation.json';$corrPath=Join-Path $tmp 'error-correlation.json';$recorder=Join-Path $PSScriptRoot 'record-blindspot-observation.ps1';$evaluator=Join-Path $PSScriptRoot 'evaluate-error-independence.ps1';$id='blindspot-'+[Guid]::NewGuid().ToString('n');$obs=[ordered]@{observation_id=$id;task_id='task-test';task_type='market_analysis';collaboration_id='collab-test';participant_refs=@('employee:a/agent:a','employee:b/agent:b');model_versions=@('model-a:v1','model-b:v1');claim_pack_refs=@('claim:a','claim:b');disagreement_type='shared_source_bias';final_outcome_ref='outcome:test';attribution='data';verified_by='human:owner';classification='internal_sanitized';created_at=(Get-Date).ToUniversalTime().ToString('o')};[IO.File]::WriteAllText($obsPath,($obs|ConvertTo-Json -Depth 8),[Text.UTF8Encoding]::new($false));$first=& powershell.exe -NoProfile -ExecutionPolicy Bypass -File $recorder -ObservationPath $obsPath -PassThru 2>&1;$firstCode=$LASTEXITCODE;$second=& powershell.exe -NoProfile -ExecutionPolicy Bypass -File $recorder -ObservationPath $obsPath -PassThru 2>&1;$secondCode=$LASTEXITCODE
function Eval($corr,$samples,$groups){$x=[ordered]@{task_type='market_analysis';members=@([ordered]@{id='a';error_group=$groups[0]},[ordered]@{id='b';error_group=$groups[1]});pairwise_correlations=@([ordered]@{left='a';right='b';critical_error_correlation=$corr;sample_size=$samples})};[IO.File]::WriteAllText($corrPath,($x|ConvertTo-Json -Depth 6),[Text.UTF8Encoding]::new($false));$out=& powershell.exe -NoProfile -ExecutionPolicy Bypass -File $evaluator -InputPath $corrPath -PassThru 2>&1;[pscustomobject]@{code=$LASTEXITCODE;text=($out-join"`n")}}
$incomplete=[ordered]@{task_type='market_analysis';members=@([ordered]@{id='a';error_group='factual'},[ordered]@{id='b';error_group='causal'},[ordered]@{id='c';error_group='tool'});pairwise_correlations=@([ordered]@{left='a';right='b';critical_error_correlation=.2;sample_size=10})};[IO.File]::WriteAllText($corrPath,($incomplete|ConvertTo-Json -Depth 6),[Text.UTF8Encoding]::new($false));$incompleteOut=& powershell.exe -NoProfile -ExecutionPolicy Bypass -File $evaluator -InputPath $corrPath -PassThru 2>&1;$incompleteCode=$LASTEXITCODE
$high=Eval .8 10 @('factual','causal');$low=Eval .2 10 @('factual','causal');$new=Eval .2 2 @('factual','causal');$same=Eval .2 10 @('factual','factual');$cases=@([pscustomobject]@{name='observation_recorded_once';passed=($firstCode-eq0)},[pscustomobject]@{name='history_cannot_be_overwritten';passed=($secondCode-ne0)},[pscustomobject]@{name='high_correlation_requires_reselection';passed=($high.text-match'reselect_required')},[pscustomobject]@{name='low_correlation_can_be_independent';passed=($low.text-match'eligible_as_independent_candidates')},[pscustomobject]@{name='insufficient_history_stays_shadow_only';passed=($new.text-match'shadow_only_insufficient_history')},[pscustomobject]@{name='same_error_group_rejected';passed=($same.code-ne0)},[pscustomobject]@{name='all_candidate_pairs_are_required';passed=($incompleteCode-ne0-and($incompleteOut-join"`n")-match'pairwise_history_incomplete')});$failed=@($cases|?{-not$_.passed});$r=[pscustomobject]@{passed=($failed.Count-eq0);cases=$cases;external_calls=$false;permissions_granted=$false};if($PassThru){$r|ConvertTo-Json -Depth 6}else{$cases|Format-Table -AutoSize};if($failed.Count){throw('Blindspot learning regression failed: '+(($failed.name)-join', '))}
